        services.AddXaf(Configuration, builder => {
            builder.UseApplication<dxT1271205BlazorApplication>();
            builder.Modules
                .AddConditionalAppearance()
                .Add<dxT1271205.Module.dxT1271205Module>()
                .Add<dxT1271205BlazorModule>();
            builder.ObjectSpaceProviders
                .AddXpo((serviceProvider, options) => {
                    string connectionString = null;
                    if(Configuration.GetConnectionString("ConnectionString") != null) {
                        connectionString = Configuration.GetConnectionString("ConnectionString");
                    }
#if EASYTEST
                    if(Configuration.GetConnectionString("EasyTestConnectionString") != null) {
                        connectionString = Configuration.GetConnectionString("EasyTestConnectionString");
                    }
#endif
                    ArgumentNullException.ThrowIfNull(connectionString);
                    options.ConnectionString = connectionString;
                    options.ThreadSafe = true;
                    options.UseSharedDataStoreProvider = true;
                    options.CustomCreateObjectSpaceProvider +=(context)=> mycreateOSProvider(context,options);
                })
                .AddNonPersistent();
        });


//...
   private IObjectSpaceProvider mycreateOSProvider(CustomCreateObjectSpaceProviderContext context, XPObjectSpaceProviderOptions options) {
       var dataStoreProvider = XPObjectSpaceProvider.GetDataStoreProvider(options.ConnectionString,null,options.EnablePoolingInConnectionString);
       return new CustomXPObjectSpaceProvider(dataStoreProvider,options.ThreadSafe);
   }
